-- Phát hiện index bloat
CREATE EXTENSION pgstattuple;

SELECT indexrelname,
    pg_size_pretty(pg_relation_size(indexrelid)) AS index_size,
    (pgstatindex(indexrelid)).avg_leaf_density,     -- < 70%: bloated
    (pgstatindex(indexrelid)).leaf_fragmentation    -- > 30%: fragmented
FROM pg_stat_user_indexes
WHERE indexrelname NOT LIKE 'pg_%'
ORDER BY pg_relation_size(indexrelid) DESC;

-- REINDEX CONCURRENTLY (không lock, PostgreSQL 12+)
REINDEX INDEX CONCURRENTLY idx_orders_status_created;

-- Rebuild tất cả indexes của table
REINDEX TABLE CONCURRENTLY orders;

-- pg_repack để rebuild table + indexes (ít disruptive hơn REINDEX TABLE)
-- pg_repack -t orders myapp_db

-- Kiểm tra sau rebuild
SELECT indexrelname, pg_size_pretty(pg_relation_size(indexrelid))
FROM pg_stat_user_indexes WHERE indexrelname = 'idx_orders_status_created';

-- Tự động maintenance với pg_cron
CREATE EXTENSION pg_cron;
SELECT cron.schedule('reindex-orders', '0 3 * * 0', -- Mỗi chủ nhật 3AM
    'REINDEX INDEX CONCURRENTLY idx_orders_status_created');
